import os
import pandas as pd

def add_features(df, data_type):
    """
    Add features to the DataFrame based on the data type.

    Parameters:
    df (DataFrame): The input DataFrame.
    data_type (str): The type of data ('product' or 'opportunity').

    Returns:
    DataFrame: The DataFrame with added features.
    """
    if data_type == 'product':
        # Ensure the columns are treated as strings before applying .str.replace
        df['Net'] = df['Net'].astype(str).str.replace('[\$,]', '', regex=True)
        df['Price'] = df['Price'].astype(str).str.replace('[\$,]', '', regex=True)

        # Convert relevant columns to numeric types
        df['Net'] = pd.to_numeric(df['Net'], errors='coerce')
        df['Price'] = pd.to_numeric(df['Price'], errors='coerce')

        # Calculate profit margin
        df['Profit Margin'] = (df['Net'] / df['Price']) * 100
    elif data_type == 'opportunity':
        # Create a seasonality index
        seasonality_map = {'Very Low': 1, 'Low': 2, 'Moderate': 3, 'High': 4, 'Very High': 5}
        df['Seasonality Index'] = df['Seasonality'].map(seasonality_map)
    return df

def combine_csv_files_with_features(input_folder, output_file, data_type):
    """
    Combine all CSV files in the input folder into a single CSV file and add features.

    Parameters:
    input_folder (str): The folder containing the input CSV files.
    output_file (str): The path to the output CSV file.
    data_type (str): The type of data ('product' or 'opportunity').
    """
    try:
        # List all CSV files in the input folder
        csv_files = [os.path.join(input_folder, f) for f in os.listdir(input_folder) if f.endswith('.csv')]

        # Debug: Print the list of CSV files found
        print(f"CSV files found in {input_folder}: {csv_files}")

        if not csv_files:
            print(f"No CSV files found in {input_folder}")
            return

        # Combine all CSV files into a single DataFrame
        combined_df = pd.concat([pd.read_csv(f) for f in csv_files], ignore_index=True)

        # Debug: Print the first few rows of the combined DataFrame
        print(f"First few rows of the combined DataFrame:\n{combined_df.head()}")

        # Data validation and cleaning
        combined_df.drop_duplicates(inplace=True)
        combined_df.dropna(inplace=True)

        # Add features
        combined_df = add_features(combined_df, data_type)

        # Write the combined DataFrame to a single CSV file
        combined_df.to_csv(output_file, index=False)
        print(f"Successfully combined files into {output_file}")
    except Exception as e:
        print(f"Error combining files: {e}")

# Define input and output paths
opportunity_input_folder = '/content/data/inputs/opportunities'
